import { useState, useEffect } from "react";

function App() {
  const [tarefa, setTarefa] = useState("");
  const [editandoIndex, setEditandoIndex] = useState(null);
  const [textoEditado, setTextoEditado] = useState("");
  const [filtro, setFiltro] = useState("todas");

  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (tarefa.trim() === "") return;

    const novaTarefa = { texto: tarefa, concluida: false };
    setLista([...lista, novaTarefa]);
    setTarefa("");
  }

  function removerTarefa(index) {
    setLista(lista.filter((_, i) => i !== index));
  }

  function toggleTarefa(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, concluida: !item.concluida } : item
      )
    );
  }

  function iniciarEdicao(index) {
    setEditandoIndex(index);
    setTextoEditado(lista[index].texto);
  }

  function salvarEdicao(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, texto: textoEditado } : item
      )
    );
    setEditandoIndex(null);
    setTextoEditado("");
  }

  const listaFiltrada = lista.filter((item) => {
    if (filtro === "concluidas") return item.concluida;
    if (filtro === "pendentes") return !item.concluida;
    return true;
  });

  const total = lista.length;
  const concluidas = lista.filter((t) => t.concluida).length;
  const pendentes = total - concluidas;

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>📝 To-Do List</h1>

        <div style={styles.contador}>
          <span>Total: {total}</span>
          <span>Concluídas: {concluidas}</span>
          <span>Pendentes: {pendentes}</span>
        </div>

        <div style={styles.inputArea}>
          <input
            style={styles.input}
            value={tarefa}
            onChange={(e) => setTarefa(e.target.value)}
            placeholder="Digite uma tarefa..."
          />
          <button style={styles.addButton} onClick={adicionarTarefa}>
            +
          </button>
        </div>

        <div style={styles.filtros}>
          {["todas", "concluidas", "pendentes"].map((f) => (
            <button
              key={f}
              style={{
                ...styles.filtroButton,
                background: filtro === f ? "#4A90E2" : "#E0E0E0",
                color: filtro === f ? "#fff" : "#333"
              }}
              onClick={() => setFiltro(f)}
            >
              {f === "todas"
                ? "Todas"
                : f === "concluidas"
                ? "Concluídas"
                : "Pendentes"}
            </button>
          ))}
        </div>

        <ul style={styles.lista}>
          {listaFiltrada.map((item, index) => (
            <li key={index} style={styles.item}>
              {editandoIndex === index ? (
                <input
                  style={styles.input}
                  value={textoEditado}
                  onChange={(e) => setTextoEditado(e.target.value)}
                />
              ) : (
                <span
                  style={{
                    textDecoration: item.concluida ? "line-through" : "none",
                    color: item.concluida ? "#888" : "#333",
                    fontWeight: 500
                  }}
                >
                  {item.texto}
                </span>
              )}

              <div style={styles.actions}>
                <button
                  style={{
                    ...styles.checkButton,
                    background: item.concluida ? "#7B8D8E" : "#2ECC71"
                  }}
                  onClick={() => toggleTarefa(index)}
                >
                  ✔
                </button>

                {editandoIndex === index ? (
                  <button
                    style={styles.saveButton}
                    onClick={() => salvarEdicao(index)}
                  >
                    💾
                  </button>
                ) : (
                  <button
                    style={styles.editButton}
                    onClick={() => iniciarEdicao(index)}
                  >
                    ✏️
                  </button>
                )}

                <button
                  style={styles.deleteButton}
                  onClick={() => removerTarefa(index)}
                >
                  ✖
                </button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

const styles = {
  page: {
    background: "#f0f4f8",
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "flex-start",
    paddingTop: 50,
    fontFamily: "Arial, sans-serif"
  },
  container: {
    background: "#fff",
    padding: 25,
    borderRadius: 15,
    boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
    width: 400,
    maxWidth: "90%"
  },
  title: {
    textAlign: "center",
    marginBottom: 15,
    color: "#4A90E2"
  },
  contador: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: 15,
    fontWeight: "bold",
    fontSize: 14,
    color: "#333"
  },
  inputArea: {
    display: "flex",
    gap: 10,
    marginBottom: 20
  },
  input: {
    flex: 1,
    padding: 10,
    borderRadius: 10,
    border: "1px solid #ccc",
    outline: "none",
    transition: "border 0.2s",
  },
  addButton: {
    padding: "10px 18px",
    borderRadius: 10,
    border: "none",
    background: "#4A90E2",
    color: "#fff",
    fontSize: 18,
    cursor: "pointer",
    transition: "background 0.2s",
  },
  filtros: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: 20
  },
  filtroButton: {
    flex: 1,
    padding: "8px 0",
    margin: "0 5px",
    borderRadius: 10,
    border: "none",
    cursor: "pointer",
    fontWeight: 500,
    transition: "0.2s"
  },
  lista: {
    listStyle: "none",
    padding: 0
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 12,
    borderRadius: 10,
    marginBottom: 10,
    background: "#f7f9fa",
    boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
  },
  actions: {
    display: "flex",
    gap: 5
  },
  checkButton: {
    border: "none",
    color: "#fff",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold",
    transition: "0.2s"
  },
  editButton: {
    background: "#F5A623",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold",
    transition: "0.2s"
  },
  saveButton: {
    background: "#50E3C2",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold",
    color: "#fff",
    transition: "0.2s"
  },
  deleteButton: {
    background: "#E94E77",
    color: "#fff",
    border: "none",
    padding: "6px 10px",
    borderRadius: 8,
    cursor: "pointer",
    fontWeight: "bold",
    transition: "0.2s"
  }
};

export default App;
